INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 0, 1001, 2, 1, 1.4, 0, 0, "春咲 ひより", 1, 0, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 1, 0, "お！\nあそこに困ってそうな人発見！");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("みんなみたいに\nわたしも強くならなきゃ", 0, 1002, 2, 1, 1.4, 0, 0, "草野 優衣", 1, 0, "わ、わたし、\nなに言ってるんだろ\nあはは…", 1, 0, "大切な人を\n守れるようになりたい…って");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("フェンシングを始めてみては？", 0, 1003, 2, 1, 1.4, 0, 0, "士条 怜", 1, 0, "少しは磨かれると思いますよ。", 1, 0, "キミに必要な集中力と感性が");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("ねぇ、にいちゃん！", 0, 1004, 2, 1, 1.5, 0, 0, "穂高 みそぎ", 1, 0, "みそぎはねぇ、\nかくれんぼやりたい！", 1, 0, "今日はなにして遊ぶ？");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("風宮あかりです", 0, 1006, 2, 1, 1.4, 0, 0, "風宮 あかり", 1, 0, "私といっしょに…\nいかない？", 1, 0, "ねぇ…");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("出雲宮子なのー", 0, 1007, 2, 1, 1.5, 0, 0, "出雲 宮子", 1, 0, "食べ物の恨みは怖いのー", 1, 0, "プリンたべたいのー");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("ボクは虹村雪。", 0, 1008, 2, 1, 1.4, 0, 0, "虹村 雪", 1, 0, "いいよ。\n見られることは運命さ…", 1, 0, "キミもボクの美貌に\n吸い寄せられたんだね。");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("フッ…聞いて後悔するがいい！", 0, 1009, 2, 1, 1.4, 0, 0, "柊杏奈", 1, 0, "人呼んで「疾風の冥姫」!!", 1, 0, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("マホマホ王国のプリンセス、\nまほ姫どす", 0, 1010, 2, 1, 1.5, 0, 0, "姫宮 真歩", 1, 0, "ほんまおおきにやわ～♪", 1, 0, "うさぎさん、\n運命の王子はんに巡りあわせてくれて");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("衣之咲璃乃です！", 0, 1011, 2, 1, 1.4, 0, 0, "衣之咲 璃乃", 1, 0, "ここで会ったが\n100年目～！", 1, 0, "生き別れたお兄ちゃんを探して\n三千世界！");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("私はハツネ、\n結構強いんだよ。\nきらーん☆", 0, 1012, 2, 1, 1.4, 0, 0, "柏崎 初音", 1, 0, "…って、お願い！\n誰にも言わないでおいて～！", 1, 0, "ち、超能力って…\n何のことかな～？");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("ちょす！\n美波鈴奈だよ～♪", 0, 1016, 2, 1, 1.4, 0, 0, "美波 鈴奈", 1, 0, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 1, 0, "一応カリスマ読モJKやってまっす！");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("はいたーい。\n喜屋武香織さー。", 0, 1017, 2, 1, 1.4, 0, 0, "喜屋武 香織", 1, 0, "でも、沖縄もとってもいいとこさー", 1, 0, "東京は遊園地みたいなところさー");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("支倉伊緒です。", 0, 1018, 2, 1, 1.4, 0, 0, "支倉 伊緒", 1, 0, "イオちゃんって呼んでね。", 1, 0, "先生って呼ばれるのは\nくすぐったいから");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 0, 1020, 2, 1, 1.5, 0, 0, "茜 ミミ", 1, 0, "ミミをおいてかないでぇ～", 1, 0, "あ！/\お兄ちゃ～ん\nまってよ～");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("あ…あの…えっと…\n栗…林…くるみ…です……", 0, 1021, 2, 1, 1.5, 0, 0, "栗林 くるみ", 1, 0, "ふぇぇぇぇぇん……", 1, 0, "あの……\nふぇ……");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("風宮よりです。\nあああああ！", 0, 1022, 2, 1, 1.4, 0, 0, "風宮 より", 1, 0, "なんてありがとうございます！", 1, 0, "こんな私に貴重な時間を\n割いていただき、");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("私、アヤネ！\nぷうきちと一緒についてってあげるね！", 0, 1023, 2, 1, 1.5, 0, 0, "北条 綾音", 1, 0, "私こっち行きたいー\nね、早く早くー", 1, 0, "おにいちゃんどこいくの？\nえ？");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("わっ…わっ…私、\n天野すずめといいます！", 0, 1025, 2, 1, 1.4, 0, 0, "天野 すずめ", 1, 0, "これて何か違う…\nあああすみません！", 1, 0, "ふ、不束者ですが\nどうぞ末永く…って、");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("……クスクス…私は\n…倉石恵理子……", 0, 1027, 2, 1, 1.4, 0, 0, "倉石 恵理子", 1, 0, "離しませんわ………\n絶対に…!!", 1, 0, "あなたは…運命の……\n伴侶……");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 0, 1028, 2, 1, 1.4, 0, 0, "佐々木 咲恋", 1, 0, "…そうでしょ？？", 1, 0, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("桜井望だよ！\nよろしくねっ", 0, 1029, 2, 1, 1.4, 0, 0, "桜井 望", 1, 0, "あはは、\n私もまだまだだなぁ～", 1, 0, "ぇっと…\nキミ、私のこと知らないの?!");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("デケデケデンっ！", 0, 1030, 2, 1, 1.4, 0, 0, "ニノン・ジュベール", 1, 0, "ショーグン、\nワタシと一緒に天下統一デース！", 1, 0, "初めまして、\n私はニノン・ジュベール申すデス！");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("上喜しのぶです。\n手元のドクロが父です。", 0, 1031, 2, 1, 1.4, 0, 0, "上喜 しのぶ", 1, 0, "おかしいですね……", 1, 0, "でもって私の隣にいるのが……\nえ、見えない？");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("目指すはビッグな\nお笑い芸人だっぺ！", 0, 1033, 2, 1, 1.5, 0, 0, "野戸まひる", 1, 0, "そう、\nオラのボケに突っ込める相方が…！", 1, 0, "けんども\nそれには足りないモンが…");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 0, 1034, 2, 1, 1.4, 0, 0, "綾瀬 ゆかり", 1, 0, "ちょ\nちょっと一杯飲んできます…！", 1, 0, "ちょっと緊張しちゃって…");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("氷川鏡華…です", 0, 1036, 2, 1, 1.5, 0, 0, "氷川 鏡華", 1, 0, "これ以上お話しすることは…\nないです！", 1, 0, "知らない人とは話しちゃいけないので");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("柏崎…栞です。", 0, 1038, 2, 1, 1.4, 0, 0, "柏崎 栞", 1, 0, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 1, 0, "……あ、アラーム。");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("ふ、双葉碧です。", 0, 1040, 2, 1, 1.4, 0, 0, "双葉 碧", 1, 0, "野に咲く花が、\n唯一の話相手です。", 1, 0, "私、一人も友達がいなくて……");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("三角千歌です。", 0, 1042, 2, 1, 1.4, 0, 0, "三角 千歌", 1, 0, "そう思っています。", 1, 0, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("安芸真琴だ。", 0, 1043, 2, 1, 1.4, 0, 0, "安芸 真琴", 1, 0, "う、疑ってすまなかったな…", 1, 0, "あぁ？\nお前のそいつの仲間か？");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("わらわこそは夜を総べる者！", 0, 1044, 2, 1, 1.4, 0, 0, "イリヤ・オーンスタイン", 1, 0, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 1, 0, "生けとし生ける全ての者よ！");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("そこで騎士は妖精を乱暴に……", 0, 1045, 2, 1, 1.4, 0, 0, "遠見 空花", 1, 0, "ｌク、クウカに何かご用ですか!?", 1, 0, "ぐふふふふ……はっ！");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("宮坂たまきにゃ♪\n猫はいいにゃよ？", 0, 1046, 2, 1, 1.4, 0, 0, "宮坂たまき", 1, 0, "う～ん…\n猫ってホントに最高にゃ～♪", 1, 0, "自由気ままで♪\n寝て遊んで、食べてケンカして…");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("大神美冬よ！", 0, 1048, 2, 1, 1.4, 0, 0, "大神 美冬", 1, 0, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 1, 0, "それでは早速クエストに…");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("星野静流だよ！", 0, 1049, 2, 1, 1.4, 0, 0, "星野静流", 1, 0, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 1, 0, "クエストもバトルも\n掃除も洗濯も");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("アタシは玉泉美咲。", 0, 1050, 2, 1, 1.5, 0, 0, "玉泉美咲", 1, 0, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 1, 0, "見ての通りの\nセクシー美少女で");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("？？？", 0, 1052, 2, 1, 1.4, 0, 0, "リマ", 1, 0, "？？？？", 1, 0, "？？？？");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("モニカ・ヴァイスヴィントだ。", 0, 1053, 2, 1, 1.5, 0, 0, "モニカ・ヴァイスヴィント", 1, 0, "そ、そこまでいうなら\nもらってやる", 1, 0, "菓子でつろうなどと\n稚拙な策を……");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("モニカ・ヴァイスヴィントだ。", 0, 1058, 2, 1, 1.5, 0, 0, "ペコリーヌ", 1, 0, "そ、そこまでいうなら\nもらってやる", 1, 0, "菓子でつろうなどと\n稚拙な策を……");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("モニカ・ヴァイスヴィントだ。", 0, 1059, 2, 1, 1.5, 0, 0, "コッコロ", 1, 0, "そ、そこまでいうなら\nもらってやる", 1, 0, "菓子でつろうなどと\n稚拙な策を……");
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("モニカ・ヴァイスヴィントだ。", 0, 1060, 2, 1, 1.5, 0, 0, "キャル", 1, 0, "そ、そこまでいうなら\nもらってやる", 1, 0, "菓子でつろうなどと\n稚拙な策を……");
